var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":"REGINA_ESPR_NULL_NULL","text":{"KOREA":"콜록……! 하악……! 하아……!","JPN":"ゴホッ……！　はあっ……！　はあ……！","ENG":"*Cough...!* *Huff...!* *Huff...!*","TWN":"咳咳……！哈啊……！哈啊……！"},"stage":{"bg":"PRYDWEN","bgm":"THEMA_ESPR_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"맥크레디 양, 호흡이 계속 멎고 있어. 역시 이건 감기라기엔…….","JPN":"マクレディー君、咳で呼吸ができないでいる。さすがにこれは風邪では……","ENG":"Regina, your breathing is irregular. I should've known this wasn't a cold...!","TWN":"麥克蕾蒂，呼吸速度一直在減緩，如果這是感冒也太……"},"stage":{"bg":"PRYDWEN","bgm":"THEMA_ESPR_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"BIO_NPC_ESPR2_NULL","text":{"KOREA":"실제로 상대해 본 소감은 어떻소, 부학회장?","JPN":"実際に相手してみた感想はどうだ、副学会長。","ENG":"What is your impression of fighting one of them, Vice President?","TWN":"實際體驗後感覺怎麼樣，副學會長？"},"stage":{"bg":"PRYDWEN","bgm":"THEMA_ESPR_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BIO_NPC_ESPR2_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"BIO_NPC_ESPR2_NULL","text":{"KOREA":"생물로서의 퍼포먼스를 전투에만 투자한 결과물이오. 감상을 들려 주면 좋겠군.","JPN":"生物としてのパフォーマンスを戦闘だけに結集させた賜物だ。感想を聞かせてほしいな。","ENG":"They are the result of investing every bit of performance for battle. I'd love to hear your input.","TWN":"這是把生物科技投入到戰鬥中的成果。希望你能說出你的感想。"},"stage":{"bg":"PRYDWEN","bgm":"THEMA_ESPR_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BIO_NPC_ESPR2_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"SILKY_NPC_ESPR2_NULL","text":{"KOREA":"호, 혼자서는 더 이상 무리예요. 루나 님도 저쪽으로 돌아서셨잖아요.","JPN":"ひ、一人ではもう無理です。ルナ様もあっち側につかれたじゃないですか。","ENG":"Y-you can't fight them all on her own. Even Ms. Luna turned against us.","TWN":"你…你一個人撐不住的。露娜不是也投向那邊了嘛。"},"stage":{"bg":"PRYDWEN","bgm":"THEMA_ESPR_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SILKY_NPC_ESPR2_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"SILKY_NPC_ESPR2_NULL","text":{"KOREA":"기관 사람이면 학회를 괴롭히는 나쁜 악당이라고요! 레지나 님이 감싸 주실 필요는……!","JPN":"機関の人といえば学会をいじめるひどい悪党です！　レジーナ様が庇ってさしあげる必要は……！","ENG":"Institution agents are villains who prey on the Society! You have no reason to protec–!","TWN":"機關的人一直是阻礙學會的礙事者！蕾佳娜大人沒必要保護……！"},"stage":{"bg":"PRYDWEN","bgm":"THEMA_ESPR_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SILKY_NPC_ESPR2_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"REGINA_ESPR_NULL_NULL","text":{"KOREA":"아뇨. 저는…… 저 자들이 저지르는 미친 짓을 도저히 납득할 수 없어요.","JPN":"いいえ。私は……あの者たちの狂気じみた行動を納得することは到底できませんわ。","ENG":"No. But I... I cannot possibly accept the insanity they have caused.","TWN":"不，我……我實在無法接受他們做出的瘋狂行為。"},"stage":{"bg":"PRYDWEN","bgm":"THEMA_ESPR_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"REGINA_ESPR_NULL_NULL","text":{"KOREA":"……가문의 명예를 위해서라도.","JPN":"……家門の名誉のためにも。","ENG":"...This is my way of protecting my family's honor.","TWN":"……哪怕是為了家族的榮譽。"},"stage":{"bg":"PRYDWEN","bgm":"THEMA_ESPR_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"BIO_NPC_ESPR2_NULL","text":{"KOREA":"흠. 상식이니 윤리니 떠들어댈 때보다는 좋은 눈빛이로군.","JPN":"ふむ。常識だの倫理だのと話していたときよりは、いい目をしている。","ENG":"Hmm... I like this version of you better than the one where you were ranting about ethics and common sense.","TWN":"嗯，我喜歡你現在的眼神，比起高談闊論什麼常識和倫理的時候，強多了。"},"stage":{"bg":"PRYDWEN","bgm":"THEMA_ESPR_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BIO_NPC_ESPR2_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"BIO_NPC_ESPR2_NULL","text":{"KOREA":"하지만 수적으로도 열세인 마당에 계속 버틸 수 있겠소?","JPN":"だが数的にも劣勢であるこの状況で、これ以上耐えられるのか？","ENG":"But how much longer can you endure? You are obviously outnumbered.","TWN":"不過在數量上處於劣勢的情況下，你還能撐多久呢？"},"stage":{"bg":"PRYDWEN","bgm":"THEMA_ESPR_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BIO_NPC_ESPR2_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"REGINA_ESPR_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"PRYDWEN","bgm":"THEMA_ESPR_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"SILKY_NPC_ESPR2_NULL","text":{"KOREA":"부학회장님…….","JPN":"副学会長様……","ENG":"Ms. Vice President...","TWN":"副學會長……"},"stage":{"bg":"PRYDWEN","bgm":"THEMA_ESPR_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SILKY_NPC_ESPR2_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"SENA_HARMONY_NULL_NULL","text":{"KOREA":"소장님, 슬슬 그만 가지고 놀고 이만 마무리하는 게 어때?","JPN":"所長、そろそろ弄ぶのはやめてもう終わりにしたらどう？","ENG":"Chief Heydrich, why don't you stop fooling around and wrap it up already?","TWN":"所長，別再繼續玩了，現在結束戰鬥怎麼樣？"},"stage":{"bg":"PRYDWEN","bgm":"THEMA_ESPR_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SENA_HARMONY_NULL_NULL","face":"UNIT_PRIDE"},"C":null,"R":{"char_id":"TRUMPET_HARMONY_ESPR2_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L18_1","type":"dialog","speaker":"SENA_HARMONY_NULL_NULL","text":{"KOREA":"집 나간 꼬마도 돌아왔겠다, 의식이 지연되면 학회장님도 심기가 불편해지실 것 같은데.","JPN":"家出したガキも戻ってきたし、儀式が遅れたら学会長もご機嫌斜めになるはずだわ。","ENG":"Our little runaway has returned home, and the President will be upset if the ritual is delayed any longer.","TWN":"離家出走的小鬼應該也回來了，儀式推遲的話，學會長也會不高興的。"},"stage":{"bg":"PRYDWEN","bgm":"THEMA_ESPR_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SENA_HARMONY_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"TRUMPET_HARMONY_ESPR2_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L19_1","type":"dialog","speaker":"TRUMPET_HARMONY_ESPR2_NULL","text":{"KOREA":"셰, 셰나. 그래도 부학회장인데, 살살…….","JPN":"しぇ、シェナ。相手は副学会長なんだし、優しく……","ENG":"S-Shena. But she is still the Vice President. Shouldn't we–","TWN":"世…世娜，她可是副學會長，拜託你……"},"stage":{"bg":"PRYDWEN","bgm":"THEMA_ESPR_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SENA_HARMONY_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"TRUMPET_HARMONY_ESPR2_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L20_1","type":"dialog","speaker":"SENA_HARMONY_NULL_NULL","text":{"KOREA":"어른들 일이야. 모르면 조용히나 있어, 꼬마야.","JPN":"大人同士の話よ。何も知らないなら静かにしてなさい、ガキ。","ENG":"Adults are talking right now, child. So behave and keep your mouth shut.","TWN":"這是大人的事，不懂的話就閉嘴，小鬼。"},"stage":{"bg":"PRYDWEN","bgm":"THEMA_ESPR_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SENA_HARMONY_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"TRUMPET_HARMONY_ESPR2_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L21_1","type":"dialog","speaker":"TRUMPET_HARMONY_ESPR2_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"PRYDWEN","bgm":"THEMA_ESPR_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SENA_HARMONY_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"TRUMPET_HARMONY_ESPR2_NULL","face":"UNIT_IDLE"}}}},{"id":"L23_1","type":"dialog","speaker":"BIO_NPC_ESPR2_NULL","text":{"KOREA":"흠. 타당한 지적이오.","JPN":"ふむ。もっともな指摘だ。","ENG":"Hmm... A valid point.","TWN":"嗯，這個指責很合理。"},"stage":{"bg":"PRYDWEN","bgm":"THEMA_ESPR_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BIO_NPC_ESPR2_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"BIO_NPC_ESPR2_NULL","text":{"KOREA":"모처럼 맥크레디 집안 사람다운 독기를 보여 줬는데, 아쉽군.","JPN":"せっかくマクレディー家らしい毒気を見せてくれたが、残念だな。","ENG":"It's a shame it has to end here, because you've demonstrated ruthlessness worthy of a MacCready.","TWN":"副學會長難得表現出了麥克蕾蒂家族的狠勁，真是可惜。"},"stage":{"bg":"PRYDWEN","bgm":"THEMA_ESPR_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BIO_NPC_ESPR2_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"BIO_NPC_ESPR2_NULL","text":{"KOREA":"CRF도 지금쯤이면 바닥을 드러냈겠지. 제압해라.","JPN":"もうCRFも尽きた頃だろう。制圧しろ。","ENG":"Her CRF should be depleted by this point. Take her.","TWN":"她的CRF現在應該沒剩多少了，馬上制服她。"},"stage":{"bg":"PRYDWEN","bgm":"THEMA_ESPR_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BIO_NPC_ESPR2_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L28_1","type":"dialog","speaker":"REGINA_ESPR_NULL_NULL","text":{"KOREA":"꺄악……!","JPN":"きゃっ……！","ENG":"Kyaaaak...!","TWN":"啊啊……！"},"stage":{"bg":"PRYDWEN","bgm":"THEMA_ESPR_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L30_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"맥크레디 양, 저들이 접근하게 둬선 안 돼!","JPN":"マクレディー君、あの者たちの接近を許してはいけない！","ENG":"Regina, don't let them get close to you!","TWN":"麥克蕾蒂，不可以讓它們靠近！"},"stage":{"bg":"PRYDWEN","bgm":"THEMA_ESPR_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SILKY_NPC_ESPR2_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L31_1","type":"dialog","speaker":"SILKY_NPC_ESPR2_NULL","text":{"KOREA":"도망치셔야 해요…. 더 싸우다간 죽을지도 몰라요!","JPN":"逃げないと……これ以上闘ったら死ぬかもしれません！","ENG":"You must run away... You might die if you keep on fighting!","TWN":"你必須逃走……再打下去，你說不定會死掉！"},"stage":{"bg":"PRYDWEN","bgm":"THEMA_ESPR_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SILKY_NPC_ESPR2_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L34_1","type":"dialog","speaker":"REGINA_ESPR_NULL_NULL","text":{"KOREA":"……실키, 제 옆에 있지 마세요. 휘말릴 수도 있어요.","JPN":"……シルキー、私のそばから離れなさい。巻き込まれるかもしれませんわ。","ENG":"Sylkie, stay away from me. Or you will get caught too.","TWN":"……思琪，別待在我身邊，說不定會被波及到。"},"stage":{"bg":"PRYDWEN","bgm":"THEMA_ESPR_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"SILKY_NPC_ESPR2_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L37_1","type":"dialog","speaker":"REGINA_ESPR_NULL_NULL","text":{"KOREA":"큭……! 아아아아악!!","JPN":"くっ……！　あああああっ！！","ENG":"Kgh...! Aaahhhh!!","TWN":"咳……！啊啊啊啊啊！！"},"stage":{"bg":"PRYDWEN","bgm":"THEMA_ESPR_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L38_1","type":"dialog","speaker":"SILKY_NPC_ESPR2_NULL","text":{"KOREA":"아, 안 돼!! 부학회장님!","JPN":"だ、ダメ！！　副学会長様！","ENG":"N-no!! Ms. Vice President!","TWN":"不…不要！！副學會長！"},"stage":{"bg":"PRYDWEN","bgm":"THEMA_ESPR_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L39_1","type":"dialog","speaker":"BIO_NPC_ESPR2_NULL","text":{"KOREA":"조금 과했나? 다리가 부러졌군.","JPN":"少しやりすぎたか？　足が折れたな。","ENG":"Was it too much? It seems her leg is broken.","TWN":"有些過分了嗎？看起來像是腿斷了。"},"stage":{"bg":"PRYDWEN","bgm":"THEMA_ESPR_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BIO_NPC_ESPR2_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L40_1","type":"dialog","speaker":"BIO_NPC_ESPR2_NULL","text":{"KOREA":"하지만 부학회장은 거의 평생을 카운터로 살았을 테지. 골절상이 주는 통증을 겪어 본 경험은 없을 거요.","JPN":"だが、副学会長はこれまでのほとんどをカウンターとして生きてきたはず。骨折がもたらす苦痛を経験したことはあるまい。","ENG":"However, since you've lived your whole life as a Counter, I'm sure you've never experienced the pain of a broken bone.","TWN":"不過副學會長幾乎當了一輩子的制裁者，應該沒經歷過骨折帶來的疼痛吧。"},"stage":{"bg":"PRYDWEN","bgm":"THEMA_ESPR_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BIO_NPC_ESPR2_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L41_1","type":"dialog","speaker":"BIO_NPC_ESPR2_NULL","text":{"KOREA":"어디, 고통을 감내하고 계속 저 무지한 자를 지키시겠소?","JPN":"どれ、苦痛に耐えてでもまだあの無知な者を守り続けるか？","ENG":"Are you still willing to suffer in order to protect this ignoramus?","TWN":"怎麼樣，你還要忍著疼痛，繼續保護那個無知之人嗎？"},"stage":{"bg":"PRYDWEN","bgm":"THEMA_ESPR_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BIO_NPC_ESPR2_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L43_1","type":"dialog","speaker":"MEMBER_PRYDWEN_NULL_NULL","text":{"KOREA":"히익……!","JPN":"ひいっ……！","ENG":"Eeeek...!","TWN":"唔……！"},"stage":{"bg":"PRYDWEN","bgm":"THEMA_ESPR_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BIO_NPC_ESPR2_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L44_1","type":"dialog","speaker":"REGINA_ESPR_NULL_NULL","text":{"KOREA":"하아……. 하…….","JPN":"はあ……は……","ENG":"*Huff...* *Huff...*","TWN":"哈啊……哈……"},"stage":{"bg":"PRYDWEN","bgm":"THEMA_ESPR_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L48_1","type":"dialog","speaker":"BIO_NPC_ESPR2_NULL","text":{"KOREA":"이 계집아이가 대신 목이 따이더라도?","JPN":"この小娘が代わりに首を斬られることになっても？","ENG":"Or even if this girl's head gets ripped off?","TWN":"不惜讓這個丫頭替他死掉？"},"stage":{"bg":"PRYDWEN","bgm":"THEMA_ESPR_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BIO_NPC_ESPR2_NULL","face":"UNIT_IDLE"},"R":{"char_id":"SILKY_NPC_ESPR2_NULL","face":"UNIT_HATE"}}}},{"id":"L49_1","type":"dialog","speaker":"SILKY_NPC_ESPR2_NULL","text":{"KOREA":"아윽! 이, 이거 놔 주세요!","JPN":"あうっ！　は、放してください！","ENG":"Augh! L-let go of me!","TWN":"啊呃！放…放開我！"},"stage":{"bg":"PRYDWEN","bgm":"THEMA_ESPR_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BIO_NPC_ESPR2_NULL","face":"UNIT_IDLE"},"R":{"char_id":"SILKY_NPC_ESPR2_NULL","face":"UNIT_IDLE"}}}},{"id":"L50_1","type":"dialog","speaker":"BIO_NPC_ESPR2_NULL","text":{"KOREA":"기관은 우리의 숙적이오. 처분을 막겠다면 그에 걸맞은 결의를 보여 주셔야지.","JPN":"機関は私たちの宿敵だ。処分の邪魔をするのならそれ相応の決意を見せてくれ。","ENG":"The Institution is our nemesis. If you are willing to go against punishment, you must show your resolve.","TWN":"機關是我們的宿敵。既然要阻止我處決他，就應該拿出相應的決心。"},"stage":{"bg":"PRYDWEN","bgm":"THEMA_ESPR_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BIO_NPC_ESPR2_NULL","face":"UNIT_SERIOUS"},"R":{"char_id":"SILKY_NPC_ESPR2_NULL","face":"UNIT_IDLE"}}}},{"id":"L1_1","type":"dialog","speaker":"BIO_NPC_ESPR2_NULL","text":{"KOREA":"고민할 시간은 얼마 없소, 부학회장.","JPN":"悩む時間はあまりないぞ、副学会長。","ENG":"There's no time to ponder, Vice President.","TWN":"你沒有多少時間考慮了，副學會長。"},"stage":{"bg":"PRYDWEN","bgm":"THEMA_ESPR_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BIO_NPC_ESPR2_NULL","face":"UNIT_IDLE"},"R":{"char_id":"SILKY_NPC_ESPR2_NULL","face":"UNIT_IDLE"}}}},{"id":"L2_1","type":"dialog","speaker":"BIO_NPC_ESPR2_NULL","text":{"KOREA":"선택하시오. 이대로 계속 부질없는 투정을 부릴지, 혹은 지금이라도 현실적인 판단을 내릴지.","JPN":"選びたまえ。このままつまらない我がままを押し通すか、あるいは今からでも現実的な判断を下すか。","ENG":"Choose. Will you keep whining like this, or will you make a sound decision now?","TWN":"選擇吧，是繼續這樣徒勞地掙扎，還是現在就做出現實的判斷。"},"stage":{"bg":"PRYDWEN","bgm":"THEMA_ESPR_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BIO_NPC_ESPR2_NULL","face":"UNIT_IDLE"},"R":{"char_id":"SILKY_NPC_ESPR2_NULL","face":"UNIT_IDLE"}}}},{"id":"L4_1","type":"dialog","speaker":"REGINA_ESPR_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"PRYDWEN","bgm":"THEMA_ESPR_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"REGINA_ESPR_NULL_NULL","text":{"KOREA":"실키는…… 안전을 보장해 줄 수 있나요?","JPN":"シルキーの……安全は保証していただけるのですね？","ENG":"Will you... ensure Sylkie's safety?","TWN":"思琪……你能保證她的安全嗎？"},"stage":{"bg":"PRYDWEN","bgm":"THEMA_ESPR_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"BIO_NPC_ESPR2_NULL","text":{"KOREA":"물론이오. 애초에 저런 하찮은 목숨 하나로 커질 소동은 아니긴 했소만.","JPN":"もちろんだ。そもそもあんなくだらない命一つで、このように騒ぐ必要もなかったしな。","ENG":"I promise. This entire conflict should not have escalated for someone with her petty life.","TWN":"當然。我本來也不是因為一條卑賤的小命才鬧出這麼大動靜的。"},"stage":{"bg":"PRYDWEN","bgm":"THEMA_ESPR_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BIO_NPC_ESPR2_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"MEMBER_PRYDWEN_NULL_NULL","text":{"KOREA":"아, 아니에요! 잘 생각해 보세요, 저 미치광이들이 약속을 지킬 리 없잖아요!","JPN":"だ、ダメです！　よく考えてみてください、あの狂人たちが約束を守るはずありません！","ENG":"N-no! Please think this through! These lunatics will never keep their promises!","TWN":"不…不要！請好好想想，那群瘋子怎麼可能會遵守承諾！"},"stage":{"bg":"PRYDWEN","bgm":"THEMA_ESPR_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BIO_NPC_ESPR2_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"BIO_NPC_ESPR2_NULL","text":{"KOREA":"너희 같이 천박한 자들은 그렇겠지. 학회는 약속을 어기지 않는다.","JPN":"貴様らのような下衆はそうだろう。学会は約束を守る。","ENG":"I'm sure that's true for vulgar people like you. But the Society always keeps its promise.","TWN":"像你們這樣膚淺的人應該是那樣吧。學會不會違背承諾。"},"stage":{"bg":"PRYDWEN","bgm":"THEMA_ESPR_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BIO_NPC_ESPR2_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"BIO_NPC_ESPR2_NULL","text":{"KOREA":"그럼 수긍한 것으로 받아들이겠소. 부학회장.","JPN":"それでは、承諾として受け取るぞ。副学会長。","ENG":"Then, I'll assume you agree to my proposition, Vice President.","TWN":"那我就當你同意了，副學會長。"},"stage":{"bg":"PRYDWEN","bgm":"THEMA_ESPR_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"BIO_NPC_ESPR2_NULL","text":{"KOREA":"끌고 가라.","JPN":"連れていけ。","ENG":"Take her away.","TWN":"帶走。"},"stage":{"bg":"PRYDWEN","bgm":"THEMA_ESPR_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BIO_NPC_ESPR2_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"MEMBER_PRYDWEN_NULL_NULL","text":{"KOREA":"제발, 난 아직 죽고 싶지 않아……! 죽고 싶지 않다고!","JPN":"お願い、私はまだ死にたくない……！　死にたくないよ！","ENG":"No, please! I don't want to die...! I don't wanna die!!","TWN":"求求你，我還不想死……！我不想死！"},"stage":{"bg":"PRYDWEN","bgm":"THEMA_ESPR_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BIO_NPC_ESPR2_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_04"},{"id":"L15_1","type":"dialog","speaker":"MEMBER_PRYDWEN_NULL_NULL","text":{"KOREA":"살려 주세요! 아무도 없어요! 누가 좀 살려 줘!!","JPN":"助けて！　誰かいなの！？　誰か助けて！！","ENG":"Mercy! Is there nobody there?! Someone! Please help me!!","TWN":"救命啊！有沒有人啊！誰來救救我啊！！"},"stage":{"bg":"PRYDWEN","bgm":"THEMA_ESPR_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BIO_NPC_ESPR2_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"MEMBER_PRYDWEN_NULL_NULL","text":{"KOREA":"지휘관님! 기, 기관장니이임! 으읍…! 읍! 으으읍!!","JPN":"指揮官！　き、機関長おお！　うぶっ……！　う！　ううう！！","ENG":"Commander! C-chief!! Mmf..! MMMMPH!!","TWN":"指揮官！機…機關長啊！嗚嗚……！嗚！嗚嗚嗚！！"},"stage":{"bg":"PRYDWEN","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BIO_NPC_ESPR2_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"BIO_NPC_ESPR2_NULL","text":{"KOREA":"좋은 결단이오, 부학회장. 약속대로 이 계집아이는 처분하지 않겠소이다.","JPN":"よい決断だ、副学会長。約束どおり、この小娘は処分しないでおこう。","ENG":"You made the right choice. As promised, I will not dispose of this one.","TWN":"你的決定是對的，副學會長。依照約定，我不會處決這丫頭。"},"stage":{"bg":"PRYDWEN","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BIO_NPC_ESPR2_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"SILKY_NPC_ESPR2_NULL","text":{"KOREA":"부학회장님, 죄송해요. 저 때문에…….","JPN":"副学会長様、すみません。私のせいで……","ENG":"Ms. Vice President, I'm sorry... Because of me...","TWN":"副學會長，對不起，都怪我……"},"stage":{"bg":"PRYDWEN","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SILKY_NPC_ESPR2_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"REGINA_ESPR_NULL_NULL","text":{"KOREA":"……아니에요, 실키. 당신에게는 아무런 잘못도 없어요.","JPN":"……いいえ、シルキー。あなたは何も悪くありませんわ。","ENG":"No, Sylkie. You did nothing wrong.","TWN":"……不，思琪。你什麼錯都沒有。"},"stage":{"bg":"PRYDWEN","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"PRYDWEN","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"BIO_NPC_ESPR2_NULL","text":{"KOREA":"자, 그러면 통제실로 안내해 드리지.","JPN":"さて、それでは統制室までご案内しよう。","ENG":"Now then. Allow me to escort you to the Control Room.","TWN":"好了，我帶你去控制室。"},"stage":{"bg":"PRYDWEN","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BIO_NPC_ESPR2_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"BIO_NPC_ESPR2_NULL","text":{"KOREA":"학회장께서 기다리고 계시오. 시간이 촉박하니 치료는 잠시 미루도록 하겠소이다.","JPN":"学会長がお待ちだ。時間が惜しいので治療はまたあとから受けていただこう。","ENG":"The President is waiting. Because time is of the essence, your treatment will be postponed for the time being.","TWN":"學會長正在等你。時間緊迫，治療就暫時往後延吧。"},"stage":{"bg":"PRYDWEN","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BIO_NPC_ESPR2_NULL","face":"UNIT_IDLE"},"R":null}}}]`);export{e as default};